234	// drainServiceEventsWithRenderer drains the event stream and returns the
235	// aggregated final/routing/progress data. When wd is non-nil it activates
236	// three wedge-prevention mechanisms:
237	//
238	//  1. Meaningful-event idle reset: the idle timer only resets on tool_call,
239	//     tool_result, and final events — not on text_delta/progress/other noise.
240	//  2. Loop detection: identical (call, result) pairs that repeat ≥4 times in
241	//     an 8-entry window trigger wd.cancel.
242	//  3. Per-tool-call timeout: a tool_call without a matching tool_result within
243	//     wd.toolCallTimeout triggers wd.cancel.
244	func drainServiceEventsWithRenderer(events <-chan agentlib.ServiceEvent, w io.Writer, renderer WorkLogRenderer, wd *drainWatchdog) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
245		var final *agentlib.ServiceFinalData
246		var routing *agentlib.ServiceRoutingDecisionData
247		var progress []agentlib.ServiceProgressData
248	
249		// Fast path: no watchdog, simple range loop with no timer overhead.
250		if wd == nil || (wd.idleTimeout == 0 && wd.toolCallTimeout == 0) {
251			for ev := range events {
252				decoded, err := agentlib.DecodeServiceEvent(ev)
253				if err != nil {
254					continue
255				}
256				switch {
257				case decoded.RoutingDecision != nil:
258					routing = decoded.RoutingDecision
259					if w != nil {
260						if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
261							_, _ = fmt.Fprint(w, line)
262						}
263					}
264				case decoded.Progress != nil:
265					progress = append(progress, *decoded.Progress)
266					if w != nil {
267						_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
268					}
269				case decoded.Final != nil:
270					final = decoded.Final
271				}
272			}
273			return final, routing, progress
274		}
275	
276		// Watchdog path: select loop so timers can fire alongside event reads.
277		ld := &loopDetector{}
278		var pendingCall *agentlib.ServiceToolCallData
279	
280		// resetIdle stops and restarts the idle timer. Only called on meaningful events.
281		var idleTimer *time.Timer
282		var idleTimerC <-chan time.Time
283		resetIdle := func() {
284			if wd.idleTimeout <= 0 {
285				return
286			}
287			if idleTimer == nil {
288				idleTimer = time.NewTimer(wd.idleTimeout)
289				idleTimerC = idleTimer.C
290				return
291			}
292			if !idleTimer.Stop() {
293				select {
294				case <-idleTimer.C:
295				default:
296				}
297			}
298			idleTimer.Reset(wd.idleTimeout)
299		}
300	
301		var toolCallTimer *time.Timer
302		var toolCallTimerC <-chan time.Time
303		startToolCallTimer := func() {
304			if wd.toolCallTimeout <= 0 {
305				return
306			}
307			if toolCallTimer == nil {
308				toolCallTimer = time.NewTimer(wd.toolCallTimeout)
309				toolCallTimerC = toolCallTimer.C
310				return
311			}
312			if !toolCallTimer.Stop() {
313				select {
314				case <-toolCallTimer.C:
315				default:
316				}
317			}
318			toolCallTimer.Reset(wd.toolCallTimeout)
319		}
320		stopToolCallTimer := func() {
321			if toolCallTimer == nil {
322				return
323			}
324			if !toolCallTimer.Stop() {
325				select {
326				case <-toolCallTimer.C:
327				default:
328				}
329			}
330			toolCallTimerC = nil
331		}
332	
333		// Arm the idle timer immediately so a session that never starts a tool
334		// call is still bounded.
335		if wd.idleTimeout > 0 {
336			idleTimer = time.NewTimer(wd.idleTimeout)
337			idleTimerC = idleTimer.C
338		}
339		defer func() {
340			if idleTimer != nil {
341				idleTimer.Stop()
342			}
343			if toolCallTimer != nil {
344				toolCallTimer.Stop()
345			}
346		}()
347	
348		for {
349			select {
350			case ev, ok := <-events:
351				if !ok {
352					return final, routing, progress
353				}
354				decoded, err := agentlib.DecodeServiceEvent(ev)
355				if err != nil {
356					continue
357				}
358				switch {
359				case decoded.ToolCall != nil:
360					// Meaningful: tool invocation starts. Reset idle, start per-call cap.
361					resetIdle()
362					startToolCallTimer()
363					callCopy := *decoded.ToolCall
364					pendingCall = &callCopy
365	
366				case decoded.ToolResult != nil:
367					// Meaningful: tool produced a result. Stop per-call timer.
368					stopToolCallTimer()
369					if pendingCall != nil {
370						key := makeLoopKey(*pendingCall, *decoded.ToolResult)
371						if ld.record(key) {
372							_, _ = fmt.Fprintf(os.Stderr, "agent: loop detected (command=%q repeated ≥4 times): cancelling\n", pendingCall.Name)
373							if wd.cancel != nil {
374								wd.cancel()
375							}
376							return final, routing, progress
377						}
378						pendingCall = nil
379					}
380					resetIdle()
381	
382				case decoded.Final != nil:
383					// Meaningful: execution complete. Stop all timers.
384					resetIdle()
385					stopToolCallTimer()
386					final = decoded.Final
387	
388				case decoded.RoutingDecision != nil:
389					// Not a meaningful progress event: routing is a one-time setup event.
390					routing = decoded.RoutingDecision
391					if w != nil {
392						if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
393							_, _ = fmt.Fprint(w, line)
394						}
395					}
396	
397				case decoded.Progress != nil:
398					// Not meaningful for idle reset: progress events are emitted for
399					// any tool activity including tight loops that make no real change.
400					progress = append(progress, *decoded.Progress)
401					if w != nil {
402						_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
403					}
404				}
405	
406			case <-idleTimerC:
407				_, _ = fmt.Fprintf(os.Stderr, "agent: idle timeout (%s without meaningful event): cancelling\n", wd.idleTimeout)
408				if wd.cancel != nil {
409					wd.cancel()
410				}
411				return final, routing, progress
412	
413			case <-toolCallTimerC:
414				name := ""
415				if pendingCall != nil {
416					name = pendingCall.Name
417				}
418				_, _ = fmt.Fprintf(os.Stderr, "agent: tool call timeout (%s, tool=%q): cancelling\n", wd.toolCallTimeout, name)
419				if wd.cancel != nil {
420					wd.cancel()
421				}
422				return final, routing, progress
423			}
424		}
425	}
426	
427	func selectedRoutingCandidateMetrics(routing *agentlib.ServiceRoutingDecisionData) (int, float64, float64, string) {
428		if routing == nil {
429			return 0, 0, 0, ""
430		}
431		for _, candidate := range routing.Candidates {
432			if candidate.Eligible && candidate.Model == routing.Model {
433				return candidate.Components.Power, candidate.Components.SpeedTPS, candidate.CostUSDPer1kTokens, candidate.CostSource
434			}
435		}
436		return 0, 0, 0, ""
437	}
