// record. It is called once in-stream when the routing_decision event arrives,
// so the watchdog sees a non-empty route and does not fire on healthy no-pin
// attempts. Guards: beadID must match CurrentBead (cross-attempt calls are
// no-ops); empty args leave existing values unchanged; same mutex discipline as
// SetAttempt.
func (r *SidecarLivenessReporter) UpdateRoute(beadID, harness, model, route string) {
	if r == nil {
		return
	}
	r.mu.Lock()
	defer r.mu.Unlock()
	if r.rec.CurrentBead != beadID {
		return
	}
	if harness != "" {
		r.rec.Harness = harness
	}
	if model != "" {
		r.rec.Model = model
	}
	if route != "" {
		r.rec.Route = route
	}
}

