// TestSidecarLiveness_UpdateRoute verifies AC #1: UpdateRoute propagates
// fizeau-resolved route fields into the liveness snapshot, guards on beadID
// mismatch (no-op), and does not blank existing values when args are empty.
func TestSidecarLiveness_UpdateRoute(t *testing.T) {
	projectRoot := t.TempDir()
	rep := work.NewSidecarLivenessReporter(projectRoot, "wkr-route", "sess-route", nil)
	rep.SetAttempt("bead-1", "att-1", "running", "", "", "", "", 0)

	// Initial state: harness/model/route empty.
	snap := rep.Snapshot()
	require.Empty(t, snap.Harness)
	require.Empty(t, snap.Model)
	require.Empty(t, snap.Route)

	// UpdateRoute with matching beadID populates all three fields.
	rep.UpdateRoute("bead-1", "fiz", "sonnet-4.6", "anthropic")
	snap = rep.Snapshot()
	require.Equal(t, "fiz", snap.Harness)
	require.Equal(t, "sonnet-4.6", snap.Model)
	require.Equal(t, "anthropic", snap.Route)

	// CurrentBead mismatch is a no-op: existing values must be unchanged.
	rep.UpdateRoute("bead-other", "other-h", "other-m", "other-r")
	snap = rep.Snapshot()
	require.Equal(t, "fiz", snap.Harness, "mismatch beadID must not overwrite Harness")
	require.Equal(t, "sonnet-4.6", snap.Model, "mismatch beadID must not overwrite Model")
	require.Equal(t, "anthropic", snap.Route, "mismatch beadID must not overwrite Route")

	// Empty args do not blank existing values.
	rep.UpdateRoute("bead-1", "", "", "")
	snap = rep.Snapshot()
	require.Equal(t, "fiz", snap.Harness, "empty harness must not blank existing value")
	require.Equal(t, "sonnet-4.6", snap.Model, "empty model must not blank existing value")
	require.Equal(t, "anthropic", snap.Route, "empty route must not blank existing value")
}

