// makeRoutingDecisionEvent builds a routing_decision ServiceEvent with the
// given harness, provider, and model for use in drain tests.
func makeRoutingDecisionEvent(h, p, m string) agentlib.ServiceEvent {
	payload, _ := json.Marshal(map[string]any{
		"harness":  h,
		"provider": p,
		"model":    m,
	})
	return agentlib.ServiceEvent{
		Type: agentlib.ServiceEventTypeRoutingDecision,
		Time: time.Now(),
		Data: payload,
	}
}

// TestDrainServiceEvents_OnRouteResolved_NoWatchdog verifies AC #2 (no-watchdog
// branch): onRouteResolved fires once with the resolved triple before Final.
func TestDrainServiceEvents_OnRouteResolved_NoWatchdog(t *testing.T) {
	events := make(chan agentlib.ServiceEvent, 4)
	events <- makeRoutingDecisionEvent("fiz", "anthropic", "claude-sonnet-4-6")
	events <- makeFinalEvent("success")
	close(events)

	var gotH, gotP, gotM string
	callCount := 0
	cb := func(h, p, m string) {
		callCount++
		gotH, gotP, gotM = h, p, m
	}

	final, _, _ := drainServiceEventsWithRenderer(events, nil, NewWorkLogRenderer(WorkLogRendererOptions{WorkPhase: "do"}), nil, cb)
	require.NotNil(t, final)
	assert.Equal(t, 1, callCount, "onRouteResolved must fire exactly once")
	assert.Equal(t, "fiz", gotH)
	assert.Equal(t, "anthropic", gotP)
	assert.Equal(t, "claude-sonnet-4-6", gotM)
}

