// TestProgressWatchdog_PopulatedRoute_DoesNotFire verifies AC #3: an attempt
// whose liveness snapshot carries a non-empty route field is NOT flagged
// wedged by the watchdog even when the running budget is exceeded. The
// all-empty frozen case still fires.
func TestProgressWatchdog_PopulatedRoute_DoesNotFire(t *testing.T) {
	base := time.Date(2026, 6, 2, 12, 0, 0, 0, time.UTC)
	budgets := PhaseBudgets{Resolving: 5 * time.Minute, Running: 30 * time.Minute}

	// Non-empty route: watchdog must never fire regardless of elapsed time.
	wd := &progressWatchdog{budgets: budgets}
	fired, _ := wd.observe(base, string(PhaseRunning), "fiz", "claude-sonnet-4-6", "anthropic")
	require.False(t, fired, "non-empty harness must not fire watchdog")

	fired, _ = wd.observe(base.Add(31*time.Minute), string(PhaseRunning), "fiz", "claude-sonnet-4-6", "anthropic")
	require.False(t, fired, "non-empty route past running budget must NOT fire watchdog")

	// All-empty frozen case: must still fire after the running budget.
	wd2 := &progressWatchdog{budgets: budgets}
	fired, _ = wd2.observe(base, string(PhaseRunning), "", "", "")
	require.False(t, fired, "first all-empty observation starts the timer but does not fire")

	fired, _ = wd2.observe(base.Add(31*time.Minute), string(PhaseRunning), "", "", "")
	require.True(t, fired, "all-empty past running budget must fire watchdog")
}

